import { motion } from 'framer-motion';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { Code2, PenTool, Zap, User } from 'lucide-react';

const navItems = [
  { href: '/', label: '首页', icon: Code2 },
  { href: '/posts', label: '文章', icon: PenTool },
  { href: '/projects', label: '项目', icon: Zap },
  { href: '/about', label: '关于', icon: User },
];

export default function Navigation() {
  const pathname = usePathname();

  return (
    <nav className="fixed top-0 left-0 right-0 z-50 px-6 py-4">
      <div className="max-w-7xl mx-auto">
        <motion.div
          className="glass-card px-6 py-3 flex items-center justify-between"
          initial={{ y: -100, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ duration: 0.5 }}
        >
          <Link href="/">
            <motion.div
              className="flex items-center gap-2 text-2xl font-bold gradient-text cursor-pointer"
              whileHover={{ scale: 1.05 }}
            >
              <Code2 className="w-8 h-8" />
              <span>DevBlog</span>
            </motion.div>
          </Link>

          <div className="flex items-center gap-1">
            {navItems.map((item, index) => {
              const Icon = item.icon;
              const isActive = pathname === item.href;

              return (
                <Link key={item.href} href={item.href}>
                  <motion.button
                    className={`magnetic-button px-4 py-2 rounded-lg flex items-center gap-2 transition-all
                      ${isActive 
                        ? 'bg-gradient-to-r from-neon-blue to-neon-purple text-white' 
                        : 'text-gray-400 hover:text-white hover:bg-glass-hover'
                      }`}
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ duration: 0.3, delay: index * 0.1 }}
                    whileHover={{ scale: 1.1 }}
                    whileTap={{ scale: 0.95 }}
                  >
                    <Icon className="w-4 h-4" />
                    <span className="hidden sm:inline">{item.label}</span>
                  </motion.button>
                </Link>
              );
            })}
          </div>
        </motion.div>
      </div>
    </nav>
  );
}
"}

