import { useRef, useMemo } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Stars } from '@react-three/drei';
import * as THREE from 'three';

function FloatingOrb({ position, color, scale }: { position: [number, number, number]; color: string; scale: number }) {
  const meshRef = useRef<THREE.Mesh>(null);
  const time = useRef(0);

  useFrame((state, delta) => {
    time.current += delta;
    if (meshRef.current) {
      meshRef.current.position.y = position[1] + Math.sin(time.current * 0.5) * 0.5;
      meshRef.current.rotation.x = time.current * 0.1;
      meshRef.current.rotation.y = time.current * 0.15;
    }
  });

  return (
    <mesh ref={meshRef} position={position}>
      <sphereGeometry args={[scale, 32, 32]} />
      <meshStandardMaterial
        color={color}
        transparent
        opacity={0.6}
        roughness={0.1}
        metalness={0.8}
        emissive={color}
        emissiveIntensity={0.2}
      />
    </mesh>
  );
}

function WavePlane() {
  const meshRef = useRef<THREE.Mesh>(null);

  useFrame((state, delta) => {
    if (meshRef.current) {
      meshRef.current.rotation.z = Math.sin(state.clock.elapsedTime * 0.1) * 0.05;
    }
  });

  const geometry = useMemo(() => {
    const geo = new THREE.PlaneGeometry(30, 30, 50, 50);
    const positions = geo.attributes.position;

    for (let i = 0; i < positions.count; i++) {
      const x = positions.getX(i);
      const y = positions.getY(i);
      const z = Math.sin(x * 0.5) * 0.5 + Math.cos(y * 0.5) * 0.5;
      positions.setZ(i, z);
    }

    return geo;
  }, []);

  return (
    <mesh ref={meshRef} rotation={[-Math.PI / 2, 0, 0]} position={[0, -5, 0]}>
      <primitive object={geometry} attach="geometry" />
      <meshStandardMaterial
        color="#bd00ff"
        wireframe
        transparent
        opacity={0.15}
      />
    </mesh>
  );
}

function AnimatedParticles() {
  const particlesRef = useRef<THREE.Points>(null);
  const count = 500;

  const positions = useMemo(() => {
    const pos = new Float32Array(count * 3);
    for (let i = 0; i < count * 3; i++) {
      pos[i] = (Math.random() - 0.5) * 20;
    }
    return pos;
  }, [count]);

  useFrame((state) => {
    if (particlesRef.current) {
      particlesRef.current.rotation.y = state.clock.elapsedTime * 0.05;
    }
  });

  return (
    <points ref={particlesRef}>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          count={count}
          array={positions}
          itemSize={3}
        />
      </bufferGeometry>
      <pointsMaterial
        color="#00f3ff"
        size={0.05}
        transparent
        opacity={0.6}
      />
    </points>
  );
}

function Scene() {
  return (
    <>
      <ambientLight intensity={0.5} />
      <pointLight position={[10, 10, 10]} intensity={1} color="#00f3ff" />
      <pointLight position={-10, -10, -10]} intensity={1} color="#bd00ff" />

      <Stars radius={50} depth={100} count={1000} factor={4} fade={true} />

      <FloatingOrb position={[-4, 2, -5]} color="#00f3ff" scale={1.5} />
      <FloatingOrb position={[4, -1, -3]} color="#bd00ff" scale={1} />
      <FloatingOrb position={[0, 3, -7]} color="#ff006e" scale={0.8} />

      <WavePlane />
      <AnimatedParticles />
    </>
  );
}

export default function ThreeBackground() {
  return (
    <div className="fixed inset-0 -z-10">
      <Canvas
        camera={{ position: [0, 0, 10], fov: 60 }}
        style={{ background: 'linear-gradient(135deg, #0a0a0a 0%, #1a0a2e 100%)' }}
      >
        <OrbitControls enableZoom={false} enablePan={false} autoRotate autoRotateSpeed={0.5} />
        <Scene />
      </Canvas>

      <div className="absolute inset-0 bg-gradient-to-b from-gray-950/30 via-transparent to-gray-950/80" />
    </div>
  );
}
